const lines = FILE_CONTENT.split('\n');
// Find tool registrations and their implementations
const toolDefs = [];
let currentTool = null;
let braceDepth = 0;
let capturing = false;

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  const toolMatch = line.match(/server\.tool\(\s*"([^"]+)"/);
  if (toolMatch) {
    currentTool = { name: toolMatch[1], startLine: i + 1, lines: [line] };
    capturing = true;
    braceDepth = 0;
  }
  if (capturing) {
    if (i + 1 !== currentTool.startLine) currentTool.lines.push(line);
    braceDepth += (line.match(/{/g) || []).length;
    braceDepth -= (line.match(/}/g) || []).length;
    if (braceDepth <= 0 && currentTool.lines.length > 2) {
      currentTool.endLine = i + 1;
      toolDefs.push(currentTool);
      capturing = false;
      currentTool = null;
    }
  }
}

// Print summary of each tool
console.log(`Total MCP CLI tools: ${toolDefs.length}\n`);

// Focus on tools that overlap with chat/tools
const overlapping = ['search_entities', 'get_entity_detail', 'create_provisional_decision', 
  'resolve_decision', 'check_constraints', 'create_suggestion', 'log_observation',
  'ask_question', 'update_task_status'];

for (const td of toolDefs) {
  const isOverlap = overlapping.some(n => td.name === n || td.name.includes(n.replace('create_', '').replace('log_', '')));
  if (isOverlap || td.name === 'get_context') {
    console.log(`--- ${td.name} (lines ${td.startLine}-${td.endLine}) ---`);
    // Show just the implementation body (last ~15 lines before closing)
    const impl = td.lines.slice(Math.max(0, td.lines.length - 20));
    console.log(impl.join('\n'));
    console.log('');
  } else {
    console.log(`[SKIP] ${td.name} (lines ${td.startLine}-${td.endLine})`);
  }
}

