13→export function createSearchEntitiesTool(deps: ChatToolDeps) {
14→  return tool({
15→    description:
16→      "Full-text search across the knowledge graph. Use for finding entities by keyword or topic (e.g. \"authentication decisions\", \"payment tasks\"). For listing entities by kind or status, use list_workspace_entities instead.",
17→    inputSchema: z.object({
18→      query: z.string().min(1).describe("Search query (keywords matched via BM25 full-text search)"),
19→      kinds: z.array(z.enum(["project", "feature", "task", "decision", "question", "suggestion"]))
20→        .optional()
21→        .describe("Optional filter by entity kinds"),
22→      limit: z.number().int().min(1).max(25).default(10).describe("Maximum number of results"),
23→    }),
24→    execute: async (input, options) => {
25→      const context = requireToolContext(options);
26→
27→      const results = await searchEntitiesByBm25({
28→        surreal: deps.surreal,
29→        workspaceRecord: context.workspaceRecord,
30→        query: input.query,
31→        ...(input.kinds ? { kinds: input.kinds as SearchEntityKind[] } : {}),
32→        limit: input.limit,
33→      });
34→
35→      const enriched = await Promise.all(
36→        results.map(async (row) => {
37→          const entityRecord = parseRecordIdString(row.id, [row.kind as GraphEntityTable], row.kind as GraphEntityTable);
38→          const neighbors = await listEntityNeighbors({
39→            surreal: deps.surreal,
40→            workspaceRecord: context.workspaceRecord,
41→            entityRecord,
42→            limit: 8,
43→          });
44→
45→          return {
46→            id: `${row.kind}:${row.id}`,
47→            kind: row.kind,
48→            name: row.name,
49→            confidence: Number(row.score.toFixed(4)),
50→            ...(row.status ? { status: row.status } : {}),
51→            related: neighbors.slice(0, 4).map((neighbor) => ({
52→              id: `${neighbor.kind}:${neighbor.id}`,
53→              kind: neighbor.kind,
54→              name: neighbor.name,
55→              relation: neighbor.relationKind,
56→            })),
57→          };
58→        }),
59→      );
60→
61→      return {
62→        query: input.query,
63→        results: enriched,
64→      };
65→    },
66→  });
67→}
