  1→import { tool } from "ai";
  2→import { RecordId, Surreal } from "surrealdb";
  3→import { z } from "zod";
  4→import {
  5→  listWorkspaceProjectSummaries,
  6→  listWorkspaceRecentDecisions,
  7→  listWorkspaceOpenQuestions,
  8→  resolveWorkspaceProjectRecord,
  9→} from "../../graph/queries";
 10→import { listWorkspaceOpenObservations } from "../../observation/queries";
 11→import { requireToolContext } from "./helpers";
 12→import type { ChatToolDeps } from "./types";
 13→
 14→const entityKindEnum = z.enum(["project", "feature", "task", "decision", "question", "observation"]);
 15→
 16→export function createListWorkspaceEntitiesTool(deps: ChatToolDeps) {
 17→  return tool({
 18→    description:
 19→      "List workspace entities by kind. Use this to answer questions about what entities exist (e.g. \"what decisions are there?\", \"list open questions\", \"show all tasks\"). For semantic search by topic, use search_entities instead.",
 20→    inputSchema: z.object({
 21→      kind: entityKindEnum.describe("Entity kind to list."),
 22→      status: z.string().optional().describe("Optional status filter, e.g. 'provisional', 'confirmed', 'open', 'done'."),
 23→      project: z.string().optional().describe("Optional project name or ID to scope results. Only use when the user explicitly mentions a project."),
 24→      limit: z.number().int().min(1).max(50).default(25).describe("Maximum number of results."),
 25→    }),
 26→    execute: async (input, options) => {
 27→      const context = requireToolContext(options);
 28→
 29→      const projectRecord = input.project
 30→        ? await resolveWorkspaceProjectRecord({
 31→            surreal: deps.surreal,
 32→            workspaceRecord: context.workspaceRecord,
 33→            projectInput: input.project,
 34→          })
 35→        : undefined;
 36→
 37→      if (input.kind === "project") {
 38→        const projects = await listWorkspaceProjectSummaries({
 39→          surreal: deps.surreal,
 40→          workspaceRecord: context.workspaceRecord,
 41→          limit: input.limit,
 42→        });
 43→        return {
 44→          kind: "project",
 45→          count: projects.length,
 46→          entities: projects.map((p) => ({
 47→            id: `project:${p.id}`,
 48→            name: p.name,
 49→            activeTaskCount: p.activeTaskCount,
 50→          })),
 51→        };
 52→      }
 53→
 54→      if (input.kind === "task") {
 55→        return listTasks(deps.surreal, context.workspaceRecord, projectRecord, input.status, input.limit);
 56→      }
 57→
 58→      if (input.kind === "feature") {
