 79→  // Simple keyword search across tasks, decisions, and features
 80→  // Uses basic string matching (CONTAINS) for the walking skeleton.
 81→  // Future: BM25 fulltext search.
 82→  type EntityRow = {
 83→    id: RecordId;
 84→    table: string;
 85→    title?: string;
 86→    summary?: string;
 87→    text?: string;
 88→    status?: string;
 89→  };
 90→
 91→  const results = await deps.surreal.query<[EntityRow[], EntityRow[], EntityRow[]]>(
 92→    `SELECT id, 'task' AS table, title, status FROM task WHERE workspace = $ws AND (title CONTAINS $q) LIMIT 10;
 93→     SELECT id, 'decision' AS table, summary, status FROM decision WHERE workspace = $ws AND (summary CONTAINS $q) LIMIT 10;
 94→     SELECT id, 'feature' AS table, title, status FROM feature WHERE workspace = $ws AND (title CONTAINS $q) LIMIT 10;`,
 95→    { ws: workspaceRecord, q: query },
 96→  );
 97→
 98→  const entities = [
 99→    ...(results[0] ?? []).map((row) => ({
100→      id: (row.id as RecordId).id as string,
101→      type: "task",
102→      title: row.title ?? "",
103→      status: row.status ?? "",
104→    })),
105→    ...(results[1] ?? []).map((row) => ({
106→      id: (row.id as RecordId).id as string,
107→      type: "decision",
108→      title: row.summary ?? "",
109→      status: row.status ?? "",
110→    })),
111→    ...(results[2] ?? []).map((row) => ({
112→      id: (row.id as RecordId).id as string,
113→      type: "feature",
114→      title: row.title ?? "",
115→      status: row.status ?? "",
116→    })),
117→  ];
118→
119→  return {
120→    toolUseId: "", // filled by caller
121→    content: JSON.stringify({ results: entities, count: entities.length }),
122→    isError: false,
123→  };
124→};
125→
126→/** Registry of Brain-native tool handlers, keyed by tool name. */
127→const brainToolHandlers: ReadonlyMap<string, BrainToolHandler> = new Map([
128→  ["search_entities", searchEntitiesHandler],
129→]);
130→
131→// ---------------------------------------------------------------------------
132→// Effect Boundary: executeBrainNativeTools
133→// ---------------------------------------------------------------------------
134→
135→/**
136→ * Execute all brain-native tool calls and return tool_result messages.
137→ *
138→ * - Each classified brain-native call is dispatched to its handler.
139→ * - Unknown handlers produce an error result (graceful, not HTTP 500).
140→ * - All errors are caught and returned as is_error tool_results.
141→ */
142→export async function executeBrainNativeTools(
143→  classifiedCalls: ClassifiedToolCall[],
144→  deps: ToolExecutorDeps,
145→): Promise<ToolExecutionResult[]> {
146→  const brainNativeCalls = classifiedCalls.filter(
147→    (c): c is Extract<ClassifiedToolCall, { classification: "brain-native" }> =>
148→      c.classification === "brain-native",
149→  );
150→
151→  const results: ToolExecutionResult[] = [];
152→
153→  for (const call of brainNativeCalls) {
154→    const handler = brainToolHandlers.get(call.toolUse.name);
155→
156→    if (!handler) {
157→      results.push({
158→        toolUseId: call.toolUse.id,
159→        content: JSON.stringify({
160→          error: `No handler registered for brain-native tool: ${call.toolUse.name}`,
161→        }),
162→        isError: true,
163→      });
164→      continue;
165→    }
166→
167→    const startMs = performance.now();
168→    try {
169→      const result = await handler(call.toolUse.input, deps);
170→      const durationMs = performance.now() - startMs;
171→      results.push({
172→        ...result,
173→        toolUseId: call.toolUse.id,
174→      });
175→
176→      // Fire-and-forget trace capture (do not block tool result delivery)
177→      captureToolTrace(
178→        {
179→          toolName: call.toolUse.name,
180→          workspaceId: deps.workspaceId,
181→          identityId: deps.identityId,
182→          outcome: "success",
183→          durationMs,
184→          input: call.toolUse.input as Record<string, unknown>,
185→          output: { content: result.content },
186→        },
187→        { surreal: deps.surreal },
188→      ).catch((traceError) => {
189→        log.warn("proxy.tool_executor.trace_failed", "Tool trace capture failed", {
190→          tool_name: call.toolUse.name,
191→          error: String(traceError),
192→        });
193→      });
194→    } catch (error) {
195→      const durationMs = performance.now() - startMs;
196→      log.warn("proxy.tool_executor.handler_error", "Brain-native tool execution failed", {
197→        tool_name: call.toolUse.name,
198→        tool_use_id: call.toolUse.id,
199→        error: String(error),
200→      });
201→      results.push({
202→        toolUseId: call.toolUse.id,
203→        content: JSON.stringify({
204→          error: `Tool execution failed: ${String(error)}`,
205→        }),
206→        isError: true,
207→      });
208→
209→      // Trace error outcome too
210→      captureToolTrace(
211→        {
212→          toolName: call.toolUse.name,
213→          workspaceId: deps.workspaceId,
214→          identityId: deps.identityId,
215→          outcome: "error",
216→          durationMs,
217→        },
218→        { surreal: deps.surreal },
219→      ).catch((traceError) => {
220→        log.warn("proxy.tool_executor.trace_failed", "Tool trace capture failed", {
221→          tool_name: call.toolUse.name,
222→          error: String(traceError),
223→        });
224→      });
225→    }
226→  }
227→
228→  return results;
229→}
230→
231→// ---------------------------------------------------------------------------
232→// Helper: buildToolResultMessages
233→// ---------------------------------------------------------------------------
234→
235→/**
236→ * Build an Anthropic tool_result message from execution results.
237→ * Used to construct the follow-up request in the tool use loop.
238→ */
239→export function buildToolResultMessage(
240→  results: ToolExecutionResult[],
241→): ToolResultMessage {
242→  return {
243→    role: "user",
244→    content: results.map((result) => ({
245→      type: "tool_result" as const,
246→      tool_use_id: result.toolUseId,
247→      content: result.content,
248→      ...(result.isError ? { is_error: true } : {}),
249→    })),
250→  };
251→}
252→
253→// ---------------------------------------------------------------------------
254→// Response Sanitization (Pure Functions)
255→// ---------------------------------------------------------------------------
256→
257→/** Headers that must be stripped from integration HTTP responses. */
258→const SENSITIVE_HEADERS: ReadonlySet<string> = new Set([
259→  "authorization",
260→  "set-cookie",
261→  "x-api-key",
262→  "www-authenticate",
263→]);
264→
265→/** JSON field names (lowercase) that must be recursively stripped from response bodies. */
266→const SENSITIVE_FIELDS: ReadonlySet<string> = new Set([
267→  "access_token",
268→  "refresh_token",
269→  "api_key",
270→  "password",
271→  "client_secret",
272→  "bearer_token",
273→]);
274→
275→/** Maximum response body size in bytes before truncation. */
276→const MAX_RESPONSE_BYTES = 100 * 1024; // 100KB
277→
278→/**
279→ * Strip sensitive headers from an HTTP response headers map.
280→ * Pure function: returns a new record with sensitive headers removed.
281→ */
282→export function sanitizeResponseHeaders(
283→  headers: Record<string, string>,
284→): Record<string, string> {
285→  const sanitized: Record<string, string> = {};
286→  for (const [key, value] of Object.entries(headers)) {
287→    if (!SENSITIVE_HEADERS.has(key.toLowerCase())) {
288→      sanitized[key] = value;
289→    }
290→  }
291→  return sanitized;
292→}
293→
294→/**
295→ * Recursively strip sensitive fields from a JSON value.
296→ * Pure function: returns a new value with credential fields removed.
297→ */
298→export function sanitizeResponseBody(value: unknown): unknown {
299→  if (value === null || value === undefined) return value;
300→
301→  if (Array.isArray(value)) {
302→    return value.map(sanitizeResponseBody);
303→  }
304→
305→  if (typeof value === "object") {
306→    const sanitized: Record<string, unknown> = {};
307→    for (const [key, fieldValue] of Object.entries(value as Record<string, unknown>)) {
308→      if (!SENSITIVE_FIELDS.has(key.toLowerCase())) {
309→        sanitized[key] = sanitizeResponseBody(fieldValue);
310→      }
311→    }
312→    return sanitized;
313→  }
314→
315→  return value;
316→}
317→
318→/**
319→ * Truncate a string to the maximum allowed byte size.
320→ * Pure function: appends a truncation marker if the content exceeds the limit.
321→ */
322→export function truncateResponse(content: string): string {
323→  const encoder = new TextEncoder();
324→  const bytes = encoder.encode(content);
325→  if (bytes.length <= MAX_RESPONSE_BYTES) return content;
326→
327→  const truncated = new TextDecoder().decode(bytes.slice(0, MAX_RESPONSE_BYTES));
328→  return `${truncated}\n\n[Response truncated: ${bytes.length} bytes exceeds ${MAX_RESPONSE_BYTES} byte limit]`;
329→}
330→
331→/**
332→ * Full sanitization pipeline for integration tool responses.
333→ * Pure function: sanitize body -> truncate -> return content string.
334→ */
335→export function sanitizeIntegrationResponse(
336→  responseBody: string,
337→  responseHeaders: Record<string, string>,
338→): { content: string; sanitizedHeaders: Record<string, string> } {
339→  const sanitizedHeaders = sanitizeResponseHeaders(responseHeaders);
340→
341→  // Try to parse and sanitize JSON body
342→  let sanitizedContent: string;
343→  try {
344→    const parsed = JSON.parse(responseBody);
345→    const sanitized = sanitizeResponseBody(parsed);
346→    sanitizedContent = JSON.stringify(sanitized);
347→  } catch {
348→    // Not JSON -- use raw body
349→    sanitizedContent = responseBody;
350→  }
351→
352→  const truncatedContent = truncateResponse(sanitizedContent);
353→
354→  return { content: truncatedContent, sanitizedHeaders };
355→}
356→
357→// ---------------------------------------------------------------------------
358→// Effect Boundary: executeIntegrationTools
359→// ---------------------------------------------------------------------------
360→
361→/**
362→ * Execute all integration tool calls via HTTP with brokered credentials.
363→ *
364→ * For each integration tool call:
365→ *   1. Resolve credentials via credential-resolver
366→ *   2. Execute HTTP call to integration API
367→ *   3. Sanitize response (strip auth headers + credential fields)
368→ *   4. Truncate to 100KB
369→ *   5. Return as tool_result
370→ *   6. Write trace record
371→ *
372→ * Errors are returned as is_error tool_results, never thrown as exceptions.
373→ */
374→export async function executeIntegrationTools(
375→  classifiedCalls: ClassifiedToolCall[],
376→  deps: IntegrationExecutorDeps,
377→): Promise<ToolExecutionResult[]> {
378→  const integrationCalls = classifiedCalls.filter(
379→    (c): c is Extract<ClassifiedToolCall, { classification: "integration" }> =>
380→      c.classification === "integration",
381→  );
382→
383→  const results: ToolExecutionResult[] = [];
384→
385→  for (const call of integrationCalls) {
386→    const startMs = performance.now();
387→    const providerRef = call.resolvedTool.toolkit;
388→
389→    try {
390→      // Step 1: Resolve credentials
391→      if (!deps.identityId) {
392→        results.push({
393→          toolUseId: call.toolUse.id,
394→          content: JSON.stringify({ error: "Identity required for integration tool calls" }),
395→          isError: true,
396→        });
397→        continue;
398→      }
399→
400→      const credentialResolverDeps: CredentialResolverDeps = {
401→        surreal: deps.surreal,
402→        toolEncryptionKey: deps.toolEncryptionKey,
403→      };
404→
405→      const credResult = await resolveCredentialsForTool(
406→        call.toolUse.name,
407→        deps.identityId,
408→        credentialResolverDeps,
409→      );
410→
411→      if (!credResult.ok) {
412→        const durationMs = performance.now() - startMs;
413→        results.push({
414→          toolUseId: call.toolUse.id,
415→          content: JSON.stringify({ error: `Credential resolution failed: ${credResult.error}` }),
416→          isError: true,
417→        });
418→
419→        captureToolTrace(
420→          {
421→            toolName: call.toolUse.name,
422→            workspaceId: deps.workspaceId,
423→            identityId: deps.identityId,
424→            outcome: "error",
425→            durationMs,
426→            input: { tool_kind: "integration", credential_provider: providerRef },
427→          },
428→          { surreal: deps.surreal },
429→        ).catch((traceError) => {
430→          log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
431→            tool_name: call.toolUse.name,
432→            error: String(traceError),
433→          });
434→        });
435→        continue;
436→      }
437→
438→      // Step 2: Build and execute HTTP request
439→      // The tool input should contain the endpoint URL or we derive it from provider config
440→      const endpointUrl = typeof call.toolUse.input.endpoint_url === "string"
441→        ? call.toolUse.input.endpoint_url
442→        : typeof call.toolUse.input.url === "string"
443→          ? call.toolUse.input.url
444→          : undefined;
445→
446→      if (!endpointUrl) {
447→        const durationMs = performance.now() - startMs;
448→        results.push({
449→          toolUseId: call.toolUse.id,
450→          content: JSON.stringify({ error: "Integration tool call missing endpoint_url or url in input" }),
451→          isError: true,
452→        });
453→
454→        captureToolTrace(
455→          {
456→            toolName: call.toolUse.name,
457→            workspaceId: deps.workspaceId,
458→            identityId: deps.identityId,
459→            outcome: "error",
460→            durationMs,
461→            input: { tool_kind: "integration", credential_provider: providerRef },
462→          },
463→          { surreal: deps.surreal },
464→        ).catch((traceError) => {
465→          log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
466→            tool_name: call.toolUse.name,
467→            error: String(traceError),
468→          });
469→        });
470→        continue;
471→      }
472→
473→      const httpMethod = typeof call.toolUse.input.method === "string"
474→        ? call.toolUse.input.method.toUpperCase()
475→        : "POST";
476→
477→      const requestHeaders: Record<string, string> = {
478→        "Content-Type": "application/json",
479→        ...credResult.headers,
480→      };
481→
482→      // Build request body from tool input (excluding meta fields)
483→      const { endpoint_url: _eu, url: _u, method: _m, ...bodyInput } = call.toolUse.input;
484→      const hasBody = httpMethod !== "GET" && httpMethod !== "HEAD" && Object.keys(bodyInput).length > 0;
485→
486→      const fetchOptions: RequestInit = {
487→        method: httpMethod,
488→        headers: requestHeaders,
489→        ...(hasBody ? { body: JSON.stringify(bodyInput) } : {}),
490→      };
491→
492→      const httpResponse = await fetch(endpointUrl, fetchOptions);
493→      const responseBody = await httpResponse.text();
494→      const durationMs = performance.now() - startMs;
495→
496→      // Step 3-4: Sanitize and truncate
497→      const responseHeaders: Record<string, string> = {};
498→      httpResponse.headers.forEach((value, key) => {
499→        responseHeaders[key] = value;
500→      });
501→
502→      const { content } = sanitizeIntegrationResponse(responseBody, responseHeaders);
503→
504→      // Step 5: Return as tool_result
505→      const isError = httpResponse.status >= 400;
506→      const resultContent = isError
507→        ? JSON.stringify({
508→            error: `Integration API returned ${httpResponse.status}`,
509→            status: httpResponse.status,
510→            body: content,
511→          })
512→        : content;
513→
514→      results.push({
515→        toolUseId: call.toolUse.id,
516→        content: resultContent,
517→        isError,
518→      });
519→
520→      // Step 6: Write trace record
521→      captureToolTrace(
522→        {
523→          toolName: call.toolUse.name,
524→          workspaceId: deps.workspaceId,
525→          identityId: deps.identityId,
526→          outcome: isError ? "error" : "success",
527→          durationMs,
528→          input: { tool_kind: "integration", credential_provider: providerRef },
529→          output: { status: httpResponse.status, content_length: content.length },
530→        },
531→        { surreal: deps.surreal },
532→      ).catch((traceError) => {
533→        log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
534→          tool_name: call.toolUse.name,
535→          error: String(traceError),
536→        });
537→      });
538→    } catch (error) {
539→      const durationMs = performance.now() - startMs;
540→
541→      // Integration errors are tool_result errors, not HTTP 500s
542→      log.warn("proxy.integration_executor.error", "Integration tool execution failed", {
543→        tool_name: call.toolUse.name,
544→        tool_use_id: call.toolUse.id,
545→        error: String(error),
546→      });
547→
548→      results.push({
549→        toolUseId: call.toolUse.id,
550→        content: JSON.stringify({
551→          error: `Integration tool execution failed: ${String(error)}`,
552→        }),
553→        isError: true,
554→      });
555→
556→      captureToolTrace(
557→        {
558→          toolName: call.toolUse.name,
559→          workspaceId: deps.workspaceId,
560→          identityId: deps.identityId,
561→          outcome: "error",
562→          durationMs,
563→          input: { tool_kind: "integration", credential_provider: providerRef },
564→        },
565→        { surreal: deps.surreal },
566→      ).catch((traceError) => {
567→        log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
568→          tool_name: call.toolUse.name,
569→          error: String(traceError),
570→        });
571→      });
572→    }
573→  }
574→
575→  return results;
576→}
