 96→      return {
 97→        allowed: false,
 98→        reason: `Tool call denied by policy "${policy.policyTitle}": daily limit of ${policy.max_per_day} exceeded (${todayExecutionCount} calls today)`,
 99→        outcome: "denied",
100→      };
101→    }
