408→  const sanitizedHeaders = sanitizeResponseHeaders(responseHeaders);
409→
410→  // Try to parse and sanitize JSON body
411→  let sanitizedContent: string;
412→  try {
413→    const parsed = JSON.parse(responseBody);
414→    const sanitized = sanitizeResponseBody(parsed);
415→    sanitizedContent = JSON.stringify(sanitized);
416→  } catch {
417→    // Not JSON -- use raw body
418→    sanitizedContent = responseBody;
419→  }
420→
421→  const truncatedContent = truncateResponse(sanitizedContent);
422→
423→  return { content: truncatedContent, sanitizedHeaders };
424→}
425→
426→// ---------------------------------------------------------------------------
427→// Effect Boundary: executeIntegrationTools
428→// ---------------------------------------------------------------------------
429→
430→/**
431→ * Execute all integration tool calls via HTTP with brokered credentials.
432→ *
433→ * For each integration tool call:
434→ *   1. Resolve credentials via credential-resolver
435→ *   2. Execute HTTP call to integration API
436→ *   3. Sanitize response (strip auth headers + credential fields)
437→ *   4. Truncate to 100KB
438→ *   5. Return as tool_result
439→ *   6. Write trace record
440→ *
441→ * Errors are returned as is_error tool_results, never thrown as exceptions.
442→ */
443→export async function executeIntegrationTools(
444→  classifiedCalls: ClassifiedToolCall[],
445→  deps: IntegrationExecutorDeps,
446→): Promise<ToolExecutionResult[]> {
447→  const integrationCalls = classifiedCalls.filter(
448→    (c): c is Extract<ClassifiedToolCall, { classification: "integration" }> =>
449→      c.classification === "integration",
450→  );
451→
452→  const results: ToolExecutionResult[] = [];
453→
454→  for (const call of integrationCalls) {
455→    const startMs = performance.now();
456→    const providerRef = call.resolvedTool.toolkit;
457→
458→    try {
459→      // Step 0: Governance check (BEFORE credential resolution)
460→      const governancePolicies = await fetchGovernancePolicies(
461→        deps.surreal,
462→        call.toolUse.name,
463→      );
464→
465→      if (governancePolicies.length > 0) {
466→        const todayCount = await countTodayToolExecutions(
467→          deps.surreal,
468→          call.toolUse.name,
469→          deps.workspaceId,
470→        );
471→
472→        const governanceVerdict = evaluateGovernancePolicies(governancePolicies, todayCount);
473→
474→        if (!governanceVerdict.allowed) {
475→          const durationMs = performance.now() - startMs;
476→          results.push({
477→            toolUseId: call.toolUse.id,
478→            content: JSON.stringify({ error: governanceVerdict.reason }),
479→            isError: true,
480→          });
481→
482→          captureToolTrace(
483→            {
484→              toolName: call.toolUse.name,
485→              workspaceId: deps.workspaceId,
486→              identityId: deps.identityId,
487→              outcome: governanceVerdict.outcome,
488→              durationMs,
489→              input: { tool_kind: "integration", governance_denial: governanceVerdict.reason },
490→            },
491→            { surreal: deps.surreal },
492→          ).catch((traceError) => {
493→            log.warn("proxy.governance.trace_failed", "Governance trace capture failed", {
494→              tool_name: call.toolUse.name,
495→              error: String(traceError),
496→            });
497→          });
498→          continue;
499→        }
500→      }
501→
502→      // Step 0.5: Rate limit check on can_use edge
503→      if (deps.identityId) {
504→        const { maxCallsPerHour } = await fetchCanUseRateLimit(
505→          deps.surreal,
506→          deps.identityId,
507→          call.toolUse.name,
508→        );
509→
510→        if (maxCallsPerHour !== undefined) {
511→          const hourlyCount = await countHourlyToolExecutions(
512→            deps.surreal,
513→            call.toolUse.name,
514→            deps.workspaceId,
515→            deps.identityId,
516→          );
517→
518→          const rateLimitVerdict = evaluateRateLimit(maxCallsPerHour, hourlyCount);
519→
520→          if (!rateLimitVerdict.allowed) {
521→            const durationMs = performance.now() - startMs;
522→            results.push({
523→              toolUseId: call.toolUse.id,
524→              content: JSON.stringify({ error: rateLimitVerdict.reason }),
525→              isError: true,
526→            });
527→
528→            captureToolTrace(
529→              {
530→                toolName: call.toolUse.name,
531→                workspaceId: deps.workspaceId,
532→                identityId: deps.identityId,
533→                outcome: rateLimitVerdict.outcome,
534→                durationMs,
535→                input: { tool_kind: "integration", rate_limit_denial: rateLimitVerdict.reason },
536→              },
537→              { surreal: deps.surreal },
538→            ).catch((traceError) => {
539→              log.warn("proxy.rate_limit.trace_failed", "Rate limit trace capture failed", {
540→                tool_name: call.toolUse.name,
541→                error: String(traceError),
542→              });
543→            });
544→            continue;
545→          }
546→        }
547→      }
548→
549→      // Step 1: Resolve credentials
550→      if (!deps.identityId) {
551→        results.push({
552→          toolUseId: call.toolUse.id,
553→          content: JSON.stringify({ error: "Identity required for integration tool calls" }),
554→          isError: true,
555→        });
556→        continue;
557→      }
558→
559→      const credentialResolverDeps: CredentialResolverDeps = {
560→        surreal: deps.surreal,
561→        toolEncryptionKey: deps.toolEncryptionKey,
562→      };
563→
564→      const credResult = await resolveCredentialsForTool(
565→        call.toolUse.name,
566→        deps.identityId,
567→        credentialResolverDeps,
568→      );
569→
570→      if (!credResult.ok) {
571→        const durationMs = performance.now() - startMs;
572→        results.push({
573→          toolUseId: call.toolUse.id,
574→          content: JSON.stringify({ error: `Credential resolution failed: ${credResult.error}` }),
575→          isError: true,
576→        });
577→
578→        captureToolTrace(
579→          {
580→            toolName: call.toolUse.name,
581→            workspaceId: deps.workspaceId,
582→            identityId: deps.identityId,
583→            outcome: "error",
584→            durationMs,
585→            input: { tool_kind: "integration", credential_provider: providerRef },
586→          },
587→          { surreal: deps.surreal },
588→        ).catch((traceError) => {
589→          log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
590→            tool_name: call.toolUse.name,
591→            error: String(traceError),
592→          });
593→        });
594→        continue;
595→      }
596→
597→      // Step 2: Build and execute HTTP request
598→      // The tool input should contain the endpoint URL or we derive it from provider config
599→      const endpointUrl = typeof call.toolUse.input.endpoint_url === "string"
600→        ? call.toolUse.input.endpoint_url
601→        : typeof call.toolUse.input.url === "string"
602→          ? call.toolUse.input.url
603→          : undefined;
604→
605→      if (!endpointUrl) {
606→        const durationMs = performance.now() - startMs;
607→        results.push({
608→          toolUseId: call.toolUse.id,
609→          content: JSON.stringify({ error: "Integration tool call missing endpoint_url or url in input" }),
610→          isError: true,
611→        });
612→
613→        captureToolTrace(
614→          {
615→            toolName: call.toolUse.name,
616→            workspaceId: deps.workspaceId,
617→            identityId: deps.identityId,
618→            outcome: "error",
619→            durationMs,
620→            input: { tool_kind: "integration", credential_provider: providerRef },
621→          },
622→          { surreal: deps.surreal },
623→        ).catch((traceError) => {
624→          log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
625→            tool_name: call.toolUse.name,
626→            error: String(traceError),
627→          });
628→        });
629→        continue;
630→      }
631→
632→      const httpMethod = typeof call.toolUse.input.method === "string"
633→        ? call.toolUse.input.method.toUpperCase()
634→        : "POST";
635→
636→      const requestHeaders: Record<string, string> = {
637→        "Content-Type": "application/json",
638→        ...credResult.headers,
639→      };
640→
641→      // Build request body from tool input (excluding meta fields)
642→      const { endpoint_url: _eu, url: _u, method: _m, ...bodyInput } = call.toolUse.input;
643→      const hasBody = httpMethod !== "GET" && httpMethod !== "HEAD" && Object.keys(bodyInput).length > 0;
644→
645→      const fetchOptions: RequestInit = {
646→        method: httpMethod,
647→        headers: requestHeaders,
648→        ...(hasBody ? { body: JSON.stringify(bodyInput) } : {}),
649→      };
650→
651→      const httpResponse = await fetch(endpointUrl, fetchOptions);
652→      const responseBody = await httpResponse.text();
653→      const durationMs = performance.now() - startMs;
654→
655→      // Step 3-4: Sanitize and truncate
656→      const responseHeaders: Record<string, string> = {};
657→      httpResponse.headers.forEach((value, key) => {
658→        responseHeaders[key] = value;
659→      });
660→
661→      const { content } = sanitizeIntegrationResponse(responseBody, responseHeaders);
662→
663→      // Step 5: Return as tool_result
664→      const isError = httpResponse.status >= 400;
665→      const resultContent = isError
666→        ? JSON.stringify({
667→            error: `Integration API returned ${httpResponse.status}`,
668→            status: httpResponse.status,
669→            body: content,
670→          })
671→        : content;
672→
673→      results.push({
674→        toolUseId: call.toolUse.id,
675→        content: resultContent,
676→        isError,
677→      });
678→
679→      // Step 6: Write trace record
680→      captureToolTrace(
681→        {
682→          toolName: call.toolUse.name,
683→          workspaceId: deps.workspaceId,
684→          identityId: deps.identityId,
685→          outcome: isError ? "error" : "success",
686→          durationMs,
687→          input: { tool_kind: "integration", credential_provider: providerRef },
688→          output: { status: httpResponse.status, content_length: content.length },
689→        },
690→        { surreal: deps.surreal },
691→      ).catch((traceError) => {
692→        log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
693→          tool_name: call.toolUse.name,
694→          error: String(traceError),
695→        });
696→      });
697→    } catch (error) {
698→      const durationMs = performance.now() - startMs;
699→
700→      // Integration errors are tool_result errors, not HTTP 500s
701→      log.warn("proxy.integration_executor.error", "Integration tool execution failed", {
702→        tool_name: call.toolUse.name,
703→        tool_use_id: call.toolUse.id,
704→        error: String(error),
705→      });
706→
707→      results.push({
708→        toolUseId: call.toolUse.id,
709→        content: JSON.stringify({
710→          error: `Integration tool execution failed: ${String(error)}`,
711→        }),
712→        isError: true,
713→      });
714→
715→      captureToolTrace(
716→        {
717→          toolName: call.toolUse.name,
718→          workspaceId: deps.workspaceId,
719→          identityId: deps.identityId,
720→          outcome: "error",
721→          durationMs,
722→          input: { tool_kind: "integration", credential_provider: providerRef },
723→        },
724→        { surreal: deps.surreal },
725→      ).catch((traceError) => {
726→        log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
727→          tool_name: call.toolUse.name,
728→          error: String(traceError),
729→        });
730→      });
