171→const searchEntitiesHandler: BrainToolHandler = async (input, deps) => {
172→  const query = typeof input.query === "string" ? input.query : "";
173→  if (!query.trim()) return ok({ results: [], message: "Empty search query" });
174→
175→  const kinds = Array.isArray(input.kinds) ? (input.kinds as SearchEntityKind[]) : undefined;
176→  const limit = typeof input.limit === "number" ? Math.min(input.limit, 25) : 10;
177→
178→  const results = await searchEntitiesByBm25({
179→    surreal: deps.surreal,
180→    workspaceRecord: wsRecord(deps),
181→    query,
182→    ...(kinds ? { kinds } : {}),
183→    limit,
184→  });
185→
186→  const enriched = await Promise.all(
187→    results.map(async (row) => {
188→      const entityRecord = parseRecordIdString(row.id, [row.kind as GraphEntityTable], row.kind as GraphEntityTable);
189→      const neighbors = await listEntityNeighbors({
190→        surreal: deps.surreal,
191→        workspaceRecord: wsRecord(deps),
192→        entityRecord,
193→        limit: 8,
194→      });
195→
196→      return {
197→        id: `${row.kind}:${row.id}`,
198→        kind: row.kind,
199→        name: row.name,
200→        confidence: Number(row.score.toFixed(4)),
201→        ...(row.status ? { status: row.status } : {}),
202→        related: neighbors.slice(0, 4).map((neighbor) => ({
203→          id: `${neighbor.kind}:${neighbor.id}`,
204→          kind: neighbor.kind,
205→          name: neighbor.name,
206→          relation: neighbor.relationKind,
207→        })),
208→      };
209→    }),
210→  );
211→
212→  return ok({ query, results: enriched });
213→};
214→
